import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import './PatientList.css';

const PatientList = () => {
  const [patients, setPatients] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchPatients();
  }, []);

  const fetchPatients = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/patients');
      setPatients(response.data);
      setLoading(false);
    } catch (error) {
      setError('Error fetching patients');
      setLoading(false);
    }
  };

  const filteredPatients = patients.filter(patient =>
    patient.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    patient.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
    patient.phone.includes(searchTerm)
  );

  if (loading) return <div className="loading">Loading...</div>;
  if (error) return <div className="error">{error}</div>;

  return (
    <div className="patient-list">
      <div className="patient-list-header">
        <h2>Patients</h2>
        <div className="search-bar">
          <input
            type="text"
            placeholder="Search patients..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <Link to="/patients/new" className="add-patient-btn">
          Add New Patient
        </Link>
      </div>

      <div className="patients-grid">
        {filteredPatients.map((patient) => (
          <div key={patient._id} className="patient-card">
            <div className="patient-info">
              <h3>{patient.name}</h3>
              <div className="info-grid">
                <div className="info-item">
                  <span className="label">Age:</span>
                  <span>{patient.age}</span>
                </div>
                <div className="info-item">
                  <span className="label">Gender:</span>
                  <span>{patient.gender}</span>
                </div>
                <div className="info-item">
                  <span className="label">Blood Group:</span>
                  <span>{patient.bloodGroup}</span>
                </div>
                <div className="info-item">
                  <span className="label">Phone:</span>
                  <span>{patient.phone}</span>
                </div>
                <div className="info-item">
                  <span className="label">Email:</span>
                  <span>{patient.email}</span>
                </div>
              </div>

              {patient.allergies && patient.allergies.length > 0 && (
                <div className="allergies">
                  <h4>Allergies:</h4>
                  <div className="tags">
                    {patient.allergies.map((allergy, index) => (
                      <span key={index} className="tag">{allergy}</span>
                    ))}
                  </div>
                </div>
              )}

              {patient.chronicDiseases && patient.chronicDiseases.length > 0 && (
                <div className="chronic-diseases">
                  <h4>Chronic Diseases:</h4>
                  <div className="tags">
                    {patient.chronicDiseases.map((disease, index) => (
                      <span key={index} className="tag">{disease}</span>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="patient-actions">
              <Link to={`/patients/${patient._id}`} className="view-btn">
                View Details
              </Link>
              <Link to={`/patients/${patient._id}/medical-records`} className="records-btn">
                Medical Records
              </Link>
              <Link 
                to={`/appointments/new?patient=${patient._id}`} 
                className="appointment-btn"
              >
                Book Appointment
              </Link>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PatientList;
